using System;
using System.Collections.Generic;
using GTA;
using GTA.Math;
using GTA.Native;

public class CargoDeliveryMod : Script
{
    private enum GameState { Waiting, Active, Victory, Failure }

    // 终点坐标
    private static readonly Vector3 FinishPosition = new Vector3(-1042.5f, -2742.3f, 13.8f);
    private static readonly Vector3 DetourPosition = new Vector3(215.2f, -810.7f, 30.7f);

    // 任务时长 10 分钟
    private const int TaskDurationMs = 600000;
    private const int VehicleOutBufferMs = 3000;
    private const int ExplodeInvincibleMs = 800;

    // 上限
    private const int MaxPursuitVehicles = 8;
    private const int MaxEscortVehicles = 2;

    private GameState _state;
    private Vehicle _cargoVehicle;
    private Blip _finishBlip;
    private Vector3 _currentFinishPos;
    private int _taskStartTime;
    private int _outOfVehicleStart;
    private bool _isOutOfVehicle;

    // 冷却计时器 (Game.GameTime)
    private Dictionary<string, int> _cooldownEnds;

    // 效果状态
    private bool _tiresProtected;
    private int _tiresProtectEndTime;
    private bool _lowGripActive;
    private int _lowGripEndTime;
    private int _stallEndTime;
    private int _boostEndTime;
    private int _detourEndTime;
    private bool _detourActive;
    private int _explodeInvincibleEnd;

    // 生成的实体追踪
    private List<Vehicle> _spawnedVehicles;
    private List<Ped> _spawnedPeds;
    private int _enemyRelGroup;

    // 上一帧控件状态，用于模拟聊天命令触发
    private int _lastGameTime;

    public CargoDeliveryMod()
    {
        Tick += OnTick;
        Interval = 100;

        _state = GameState.Waiting;
        _cooldownEnds = new Dictionary<string, int>();
        _spawnedVehicles = new List<Vehicle>();
        _spawnedPeds = new List<Ped>();
        _cargoVehicle = null;
        _finishBlip = null;
        _currentFinishPos = FinishPosition;
        _enemyRelGroup = World.AddRelationshipGroup("CargoEnemies");
        World.SetRelationshipBetweenGroups(Relationship.Hate, _enemyRelGroup, Game.Player.Character.RelationshipGroup);
        World.SetRelationshipBetweenGroups(Relationship.Hate, Game.Player.Character.RelationshipGroup, _enemyRelGroup);

        _lastGameTime = Game.GameTime;
    }

    private void OnTick(object sender, EventArgs e)
    {
        int now = Game.GameTime;
        CleanupDeadEntities();

        // 处理爆炸后的无敌状态
        if (_explodeInvincibleEnd > 0 && now >= _explodeInvincibleEnd)
        {
            Function.Call(Hash.SET_ENTITY_INVINCIBLE, Game.Player.Character, false);
            _explodeInvincibleEnd = 0;
        }

        switch (_state)
        {
            case GameState.Waiting:
                HandleWaiting(now);
                break;
            case GameState.Active:
                HandleActive(now);
                break;
            case GameState.Victory:
            case GameState.Failure:
                HandleEnded(now);
                break;
        }
    }

    private void HandleWaiting(int now)
    {
        // 模拟聊天命令触发：使用 ReplayStartStop 控件
        if (Game.IsControlJustPressed(0, Control.ReplayStartStop))
        {
            TryStartCargo(now);
        }
    }

    private void HandleActive(int now)
    {
        // 检查失败条件
        if (CheckFailureConditions(now))
            return;

        // 检查胜利条件
        if (CheckVictoryCondition())
            return;

        // 处理效果过期
        UpdateEffects(now);

        // 更新追击车辆行为
        UpdatePursuitBehavior();

        // 更新护航车辆行为
        UpdateEscortBehavior();

        // 显示 HUD
        DrawHUD(now);

        // 处理模拟聊天命令
        HandleCommands(now);
    }

    private void HandleEnded(int now)
    {
        // 已结束，等待清理后重置
        // 清理在进入 Victory/Failure 时已完成
        DrawEndScreen();
    }

    private bool CheckFailureConditions(int now)
    {
        // 超时
        if (now - _taskStartTime >= TaskDurationMs)
        {
            SetFailure("时间到！货物未送达。");
            return true;
        }

        // 车辆不存在或已毁
        if (_cargoVehicle == null || !_cargoVehicle.Exists())
        {
            SetFailure("货物车辆已毁！");
            return true;
        }

        if (_cargoVehicle.IsDead || _cargoVehicle.Health <= 0)
        {
            SetFailure("货物车辆损毁！");
            return true;
        }

        // 玩家死亡
        if (Game.Player.Character.IsDead)
        {
            SetFailure("主播已死亡！");
            return true;
        }

        // 检查是否离开车辆
        bool playerInCargo = Game.Player.Character.IsInVehicle(_cargoVehicle);

        if (!playerInCargo)
        {
            if (!_isOutOfVehicle)
            {
                _isOutOfVehicle = true;
                _outOfVehicleStart = now;
            }
            else if (now - _outOfVehicleStart > VehicleOutBufferMs)
            {
                SetFailure("离开了货物车辆！");
                return true;
            }
        }
        else
        {
            _isOutOfVehicle = false;
        }

        return false;
    }

    private bool CheckVictoryCondition()
    {
        if (_cargoVehicle == null || !_cargoVehicle.Exists())
            return false;

        float dist = _cargoVehicle.Position.DistanceTo(_currentFinishPos);
        if (dist < 8f)
        {
            SetVictory();
            return true;
        }

        return false;
    }

    private void UpdateEffects(int now)
    {
        // 防爆轮胎过期
        if (_tiresProtected && now >= _tiresProtectEndTime)
        {
            _tiresProtected = false;
            if (_cargoVehicle != null && _cargoVehicle.Exists())
            {
                Function.Call(Hash.SET_VEHICLE_TYRES_CAN_BURST, _cargoVehicle, true);
            }
        }

        // 抓地力降低过期
        if (_lowGripActive && now >= _lowGripEndTime)
        {
            _lowGripActive = false;
            if (_cargoVehicle != null && _cargoVehicle.Exists())
            {
                Function.Call(Hash.SET_VEHICLE_REDUCE_GRIP, _cargoVehicle, false);
            }
        }

        // 引擎熄火过期
        if (_stallEndTime > 0 && now >= _stallEndTime)
        {
            _stallEndTime = 0;
            if (_cargoVehicle != null && _cargoVehicle.Exists())
            {
                _cargoVehicle.EngineRunning = true;
            }
        }

        // 加速过期
        if (_boostEndTime > 0 && now >= _boostEndTime)
        {
            _boostEndTime = 0;
        }

        // 绕路过期
        if (_detourActive && now >= _detourEndTime)
        {
            _detourActive = false;
            RestoreFinishPoint();
        }

        // 防爆轮胎期间修复轮胎
        if (_tiresProtected && _cargoVehicle != null && _cargoVehicle.Exists())
        {
            foreach (var wheel in _cargoVehicle.Wheels)
            {
                if (wheel.IsBurst)
                    wheel.Fix();
            }
        }
    }

    private void UpdatePursuitBehavior()
    {
        for (int i = _spawnedVehicles.Count - 1; i >= 0; i--)
        {
            Vehicle v = _spawnedVehicles[i];
            if (v == null || !v.Exists() || v.IsDead)
            {
                _spawnedVehicles.RemoveAt(i);
                continue;
            }

            Ped driver = v.Driver;
            if (driver != null && driver.Exists() && !driver.IsDead && _cargoVehicle != null && _cargoVehicle.Exists())
            {
                driver.Task.DriveTo(v, _cargoVehicle.Position, 15f, 40f, DrivingStyle.IgnoreLights);
            }

            // 乘客射击
            foreach (Ped passenger in v.Passengers)
            {
                if (passenger != null && passenger.Exists() && !passenger.IsDead)
                {
                    passenger.Task.ShootAt(Game.Player.Character, 5000);
                }
            }
        }
    }

    private void UpdateEscortBehavior()
    {
        for (int i = _spawnedVehicles.Count - 1; i >= 0; i--)
        {
            Vehicle v = _spawnedVehicles[i];
            if (v == null || !v.Exists() || v.IsDead)
                continue;

            // 只处理护航车（标记为有特殊司机的）
            Ped driver = v.Driver;
            if (driver == null || !driver.Exists() || driver.IsDead)
                continue;

            if (driver.RelationshipGroup != _enemyRelGroup && _cargoVehicle != null && _cargoVehicle.Exists())
            {
                // 护航车跟随玩家
                Vector3 followPos = _cargoVehicle.Position + _cargoVehicle.Velocity * 0.5f;
                driver.Task.DriveTo(v, followPos, 10f, 25f, DrivingStyle.Normal);
            }
        }

        // 同时更新独立的 Ped 列表中的护航 Ped
        for (int i = _spawnedPeds.Count - 1; i >= 0; i--)
        {
            Ped p = _spawnedPeds[i];
            if (p == null || !p.Exists() || p.IsDead)
            {
                _spawnedPeds.RemoveAt(i);
                continue;
            }

            // 非敌对的 Ped 是护航 Ped，让他们攻击附近的敌人
            if (p.RelationshipGroup != _enemyRelGroup && p.IsInVehicle())
            {
                // 搜索附近的敌人
                Ped nearestEnemy = null;
                float nearestDist = 50f;
                foreach (Ped other in World.GetNearbyPeds(p.Position, 50f))
                {
                    if (other != null && other.Exists() && !other.IsDead && other.RelationshipGroup == _enemyRelGroup)
                    {
                        float d = p.Position.DistanceTo(other.Position);
                        if (d < nearestDist)
                        {
                            nearestDist = d;
                            nearestEnemy = other;
                        }
                    }
                }
                if (nearestEnemy != null)
                {
                    p.Task.ShootAt(nearestEnemy, 3000);
                }
            }
        }
    }

    private void DrawHUD(int now)
    {
        if (_cargoVehicle == null || !_cargoVehicle.Exists())
            return;

        int remainingMs = TaskDurationMs - (now - _taskStartTime);
        if (remainingMs < 0) remainingMs = 0;
        int minutes = remainingMs / 60000;
        int seconds = (remainingMs % 60000) / 1000;

        float healthPercent = (float)_cargoVehicle.Health / _cargoVehicle.MaxHealth * 100f;
        if (healthPercent < 0f) healthPercent = 0f;

        string hudText = string.Format("~y~货物送达~w~ | 耐久: ~b~{0:0}%~w~ | 时间: ~r~{1:D2}:{2:D2}~w~",
            healthPercent, minutes, seconds);

        if (_tiresProtected)
            hudText += " | ~g~防爆轮胎~w~";
        if (_lowGripActive)
            hudText += " | ~o~低抓地力~w~";
        if (_detourActive)
            hudText += " | ~p~绕路中~w~";

        GTA.UI.Screen.ShowSubtitle(hudText, 200);
    }

    private void DrawEndScreen()
    {
        if (_state == GameState.Victory)
            GTA.UI.Screen.ShowSubtitle("~g~货物送达成功！~w~", 3000);
        else if (_state == GameState.Failure)
            GTA.UI.Screen.ShowSubtitle("~r~任务失败！~w~", 3000);
    }

    private void HandleCommands(int now)
    {
        // 使用 GTA 原生控件模拟聊天命令触发
        // 控件映射：
        //   ReplayStartStop (F1) -> !startcargo (已在 Waiting 状态处理)
        //   ReplayBack      (F2) -> repair
        //   ReplayAdvance   (F3) -> tires
        //   ReplayRecord    (F4) -> clear
        //   ReplayFwd       (F5) -> boost
        //   ReplayRewind    (F6) -> escort
        //   ReplayNewmarker (F7) -> blow
        //   ReplayDelete    (F8) -> stall
        //   ReplayCycleMarkerLeft  (F9)  -> spawn
        //   ReplayCycleMarkerRight (F10) -> lowgrip
        //   MultiplayerInfo (F11) -> explode
        //   CharacterWheel  (F12) -> detour

        if (Game.IsControlJustPressed(0, Control.ReplayBack))
            CmdRepair(now);
        if (Game.IsControlJustPressed(0, Control.ReplayAdvance))
            CmdTires(now);
        if (Game.IsControlJustPressed(0, Control.ReplayRecord))
            CmdClear(now);
        if (Game.IsControlJustPressed(0, Control.ReplayFwd))
            CmdBoost(now);
        if (Game.IsControlJustPressed(0, Control.ReplayRewind))
            CmdEscort(now);
        if (Game.IsControlJustPressed(0, Control.ReplayNewmarker))
            CmdBlow(now);
        if (Game.IsControlJustPressed(0, Control.ReplayDelete))
            CmdStall(now);
        if (Game.IsControlJustPressed(0, Control.ReplayCycleMarkerLeft))
            CmdSpawn(now);
        if (Game.IsControlJustPressed(0, Control.ReplayCycleMarkerRight))
            CmdLowGrip(now);
        if (Game.IsControlJustPressed(0, Control.MultiplayerInfo))
            CmdExplode(now);
        if (Game.IsControlJustPressed(0, Control.CharacterWheel))
            CmdDetour(now);
    }

    private bool IsOnCooldown(string cmd, int now, int cooldownMs)
    {
        if (_cooldownEnds.TryGetValue(cmd, out int endTime))
        {
            if (now < endTime)
                return true;
        }
        _cooldownEnds[cmd] = now + cooldownMs;
        return false;
    }

    private void TryStartCargo(int now)
    {
        if (_state != GameState.Waiting)
            return;

        if (IsOnCooldown("startcargo", now, 300000))
            return;

        Vehicle playerVeh = Game.Player.Character.CurrentVehicle;
        if (playerVeh == null || !playerVeh.Exists() || playerVeh.IsDead)
        {
            GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "失败", "你必须在一辆地面载具中才能开始任务！", false);
            return;
        }

        if (playerVeh.Class == VehicleClass.Boats || playerVeh.Class == VehicleClass.Helicopters || playerVeh.Class == VehicleClass.Planes)
        {
            GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "失败", "必须使用地面载具！", false);
            return;
        }

        _cargoVehicle = playerVeh;
        _cargoVehicle.Repair();
        _state = GameState.Active;
        _taskStartTime = now;
        _isOutOfVehicle = false;
        _currentFinishPos = FinishPosition;

        // 创建终点标记
        if (_finishBlip != null && _finishBlip.Exists())
            _finishBlip.Delete();
        _finishBlip = World.CreateBlip(_currentFinishPos);
        _finishBlip.Sprite = BlipSprite.Standard;
        _finishBlip.Color = BlipColor.Yellow;
        _finishBlip.Name = "货物送达终点";
        _finishBlip.IsShortRange = false;

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "开始", "易碎货物送达任务开始！10分钟内抵达终点。", false);
    }

    private void CmdRepair(int now)
    {
        if (_state != GameState.Active) return;
        if (IsOnCooldown("repair", now, 60000)) return;
        if (_cargoVehicle == null || !_cargoVehicle.Exists()) return;

        float maxHealth = _cargoVehicle.MaxHealth;
        float currentHealth = _cargoVehicle.Health;
        if (currentHealth >= maxHealth) return;

        float newHealth = currentHealth + maxHealth * 0.25f;
        if (newHealth > maxHealth) newHealth = maxHealth;
        _cargoVehicle.Health = newHealth;
        _cargoVehicle.Repair();

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "维修", "车辆修复 25%", false);
    }

    private void CmdTires(int now)
    {
        if (_state != GameState.Active) return;
        if (IsOnCooldown("tires", now, 120000)) return;
        if (_cargoVehicle == null || !_cargoVehicle.Exists()) return;

        _tiresProtected = true;
        _tiresProtectEndTime = now + 30000;
        Function.Call(Hash.SET_VEHICLE_TYRES_CAN_BURST, _cargoVehicle, false);

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "防爆", "轮胎防爆 30 秒！", false);
    }

    private void CmdClear(int now)
    {
        if (_state != GameState.Active) return;
        if (IsOnCooldown("clear", now, 90000)) return;

        int cleared = 0;
        for (int i = _spawnedVehicles.Count - 1; i >= 0; i--)
        {
            Vehicle v = _spawnedVehicles[i];
            if (v != null && v.Exists() && v.Driver != null && v.Driver.RelationshipGroup == _enemyRelGroup)
            {
                v.Delete();
                _spawnedVehicles.RemoveAt(i);
                cleared++;
            }
        }
        for (int i = _spawnedPeds.Count - 1; i >= 0; i--)
        {
            Ped p = _spawnedPeds[i];
            if (p != null && p.Exists() && p.RelationshipGroup == _enemyRelGroup)
            {
                p.Delete();
                _spawnedPeds.RemoveAt(i);
            }
        }

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "清空", string.Format("已清除 {0} 个追兵", cleared), false);
    }

    private void CmdBoost(int now)
    {
        if (_state != GameState.Active) return;
        if (IsOnCooldown("boost", now, 30000)) return;
        if (_cargoVehicle == null || !_cargoVehicle.Exists()) return;

        _boostEndTime = now + 2000;
        Vector3 forward = _cargoVehicle.ForwardVector;
        _cargoVehicle.ApplyForce(forward * 15f, Vector3.Zero, ForceType.Impulse);

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "加速", "爆发加速！", false);
    }

    private void CmdEscort(int now)
    {
        if (_state != GameState.Active) return;
        if (IsOnCooldown("escort", now, 120000)) return;
        if (_cargoVehicle == null || !_cargoVehicle.Exists()) return;

        // 检查护航车上限
        int escortCount = 0;
        foreach (var v in _spawnedVehicles)
        {
            if (v != null && v.Exists() && v.Driver != null && v.Driver.RelationshipGroup != _enemyRelGroup)
                escortCount++;
        }
        if (escortCount >= MaxEscortVehicles)
        {
            GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "护航", "护航车已达上限", false);
            return;
        }

        Vector3 spawnPos = _cargoVehicle.Position + _cargoVehicle.RightVector * 8f + Vector3.WorldUp * 2f;
        Vehicle escortVeh = World.CreateVehicle(VehicleHash.Schafter2, spawnPos, _cargoVehicle.Heading);
        if (escortVeh == null) return;

        escortVeh.PrimaryColor = System.Drawing.Color.Black;
        escortVeh.SecondaryColor = System.Drawing.Color.Black;
        _spawnedVehicles.Add(escortVeh);

        Ped driver = escortVeh.CreatePedOnSeat(VehicleSeat.Driver, PedHash.Army01GMM);
        if (driver != null)
        {
            driver.Weapons.Give(WeaponHash.SMG, 500, true, true);
            driver.RelationshipGroup = Game.Player.Character.RelationshipGroup;
            _spawnedPeds.Add(driver);
        }

        Ped gunner = escortVeh.CreatePedOnSeat(VehicleSeat.RightFront, PedHash.Army01GMM);
        if (gunner != null)
        {
            gunner.Weapons.Give(WeaponHash.AssaultRifle, 500, true, true);
            gunner.RelationshipGroup = Game.Player.Character.RelationshipGroup;
            _spawnedPeds.Add(gunner);
        }

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "护航", "护航车已派出！", false);
    }

    private void CmdBlow(int now)
    {
        if (_state != GameState.Active) return;
        if (_tiresProtected) return; // 防爆期间静默吞掉
        if (IsOnCooldown("blow", now, 30000)) return;
        if (_cargoVehicle == null || !_cargoVehicle.Exists()) return;

        int wheelsCount = _cargoVehicle.Wheels.Count;
        if (wheelsCount == 0) return;

        Random rnd = new Random();
        int burstCount = rnd.Next(1, 3);
        if (burstCount > wheelsCount) burstCount = wheelsCount;

        List<int> indices = new List<int>();
        for (int i = 0; i < wheelsCount; i++) indices.Add(i);
        for (int i = indices.Count - 1; i > 0; i--)
        {
            int j = rnd.Next(i + 1);
            int tmp = indices[i]; indices[i] = indices[j]; indices[j] = tmp;
        }

        for (int i = 0; i < burstCount; i++)
        {
            _cargoVehicle.Wheels[indices[i]].Burst();
        }

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "爆胎", string.Format("爆了 {0} 条轮胎！", burstCount), false);
    }

    private void CmdStall(int now)
    {
        if (_state != GameState.Active) return;
        if (IsOnCooldown("stall", now, 90000)) return;
        if (_cargoVehicle == null || !_cargoVehicle.Exists()) return;

        _cargoVehicle.EngineRunning = false;
        _stallEndTime = now + 3000;

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "熄火", "引擎熄火 3 秒！", false);
    }

    private void CmdSpawn(int now)
    {
        if (_state != GameState.Active) return;
        if (IsOnCooldown("spawn", now, 45000)) return;
        if (_cargoVehicle == null || !_cargoVehicle.Exists()) return;

        // 检查追击上限
        int pursuitCount = 0;
        foreach (var v in _spawnedVehicles)
        {
            if (v != null && v.Exists() && v.Driver != null && v.Driver.RelationshipGroup == _enemyRelGroup)
                pursuitCount++;
        }
        if (pursuitCount >= MaxPursuitVehicles)
        {
            GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "追兵", "追兵已饱和", false);
            return;
        }

        VehicleHash[] pursuitModels = { VehicleHash.Schafter2, VehicleHash.Dominator, VehicleHash.Buffalo, VehicleHash.Feltzer2 };
        Random rnd = new Random();

        for (int i = 0; i < 2; i++)
        {
            if (pursuitCount + i >= MaxPursuitVehicles) break;

            Vector3 spawnPos = _cargoVehicle.Position - _cargoVehicle.ForwardVector * 35f
                + _cargoVehicle.RightVector * (rnd.Next(-8, 9))
                + Vector3.WorldUp * 2f;

            VehicleHash model = pursuitModels[rnd.Next(pursuitModels.Length)];
            Vehicle pursuitVeh = World.CreateVehicle(model, spawnPos, _cargoVehicle.Heading + 180f);
            if (pursuitVeh == null) continue;

            pursuitVeh.PrimaryColor = System.Drawing.Color.DarkRed;
            _spawnedVehicles.Add(pursuitVeh);

            Ped driver = pursuitVeh.CreatePedOnSeat(VehicleSeat.Driver, PedHash.Army01GMM);
            if (driver != null)
            {
                driver.Weapons.Give(WeaponHash.Pistol, 500, true, true);
                driver.RelationshipGroup = _enemyRelGroup;
                _spawnedPeds.Add(driver);
            }

            Ped passenger = pursuitVeh.CreatePedOnSeat(VehicleSeat.RightFront, PedHash.Army01GMM);
            if (passenger != null)
            {
                passenger.Weapons.Give(WeaponHash.SMG, 500, true, true);
                passenger.RelationshipGroup = _enemyRelGroup;
                _spawnedPeds.Add(passenger);
            }
        }

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "追兵", "追击车辆已派出！", false);
    }

    private void CmdLowGrip(int now)
    {
        if (_state != GameState.Active) return;
        if (IsOnCooldown("lowgrip", now, 75000)) return;
        if (_cargoVehicle == null || !_cargoVehicle.Exists()) return;

        _lowGripActive = true;
        _lowGripEndTime = now + 15000;
        Function.Call(Hash.SET_VEHICLE_REDUCE_GRIP, _cargoVehicle, true);

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "低抓地力", "抓地力降低 60%，持续 15 秒！", false);
    }

    private void CmdExplode(int now)
    {
        if (_state != GameState.Active) return;
        if (IsOnCooldown("explode", now, 60000)) return;
        if (_cargoVehicle == null || !_cargoVehicle.Exists()) return;

        float currentHealth = _cargoVehicle.Health;
        float maxHealth = _cargoVehicle.MaxHealth;

        // 短暂无敌保护玩家
        Function.Call(Hash.SET_ENTITY_INVINCIBLE, Game.Player.Character, true);
        _explodeInvincibleEnd = now + ExplodeInvincibleMs;

        Vector3 explosionPos = _cargoVehicle.Position + _cargoVehicle.RightVector * 3f;
        World.AddExplosion(explosionPos, ExplosionType.Grenade, 3f, 0.5f, _cargoVehicle);

        // 保证车辆至少 20% 血量
        if (_cargoVehicle != null && _cargoVehicle.Exists())
        {
            float minHealth = maxHealth * 0.2f;
            if (_cargoVehicle.Health < minHealth)
                _cargoVehicle.Health = minHealth;
        }

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "爆炸", "余震安全 - 车辆血量已保护", false);
    }

    private void CmdDetour(int now)
    {
        if (_state != GameState.Active) return;
        if (IsOnCooldown("detour", now, 180000)) return;

        _detourActive = true;
        _detourEndTime = now + 120000;
        _currentFinishPos = DetourPosition;

        // 更新 Blip
        if (_finishBlip != null && _finishBlip.Exists())
            _finishBlip.Delete();
        _finishBlip = World.CreateBlip(_currentFinishPos);
        _finishBlip.Sprite = BlipSprite.Standard;
        _finishBlip.Color = BlipColor.Red;
        _finishBlip.Name = "绕路终点";
        _finishBlip.IsShortRange = false;

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "绕路", "终点已变更！120 秒后恢复。", false);
    }

    private void RestoreFinishPoint()
    {
        _currentFinishPos = FinishPosition;
        _detourActive = false;

        if (_finishBlip != null && _finishBlip.Exists())
            _finishBlip.Delete();
        _finishBlip = World.CreateBlip(_currentFinishPos);
        _finishBlip.Sprite = BlipSprite.Standard;
        _finishBlip.Color = BlipColor.Yellow;
        _finishBlip.Name = "货物送达终点";
        _finishBlip.IsShortRange = false;

        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "绕路", "终点已恢复！", false);
    }

    private void SetVictory()
    {
        _state = GameState.Victory;
        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "胜利", "货物安全送达！任务完成！", false);
        CleanupAll();
    }

    private void SetFailure(string reason)
    {
        _state = GameState.Failure;
        GTA.UI.Notification.Show(GTA.UI.NotificationIcon.Default, "货物送达", "失败", reason, false);
        CleanupAll();
    }

    private void CleanupAll()
    {
        // 清理 Blip
        if (_finishBlip != null && _finishBlip.Exists())
        {
            _finishBlip.Delete();
            _finishBlip = null;
        }

        // 清理生成的车辆和 Ped
        foreach (var v in _spawnedVehicles)
        {
            if (v != null && v.Exists())
                v.Delete();
        }
        _spawnedVehicles.Clear();

        foreach (var p in _spawnedPeds)
        {
            if (p != null && p.Exists())
                p.Delete();
        }
        _spawnedPeds.Clear();

        // 重置效果状态
        if (_cargoVehicle != null && _cargoVehicle.Exists())
        {
            Function.Call(Hash.SET_VEHICLE_TYRES_CAN_BURST, _cargoVehicle, true);
            Function.Call(Hash.SET_VEHICLE_REDUCE_GRIP, _cargoVehicle, false);
            if (_stallEndTime > 0)
                _cargoVehicle.EngineRunning = true;
        }

        _tiresProtected = false;
        _lowGripActive = false;
        _stallEndTime = 0;
        _boostEndTime = 0;
        _detourActive = false;
        _detourEndTime = 0;
        _explodeInvincibleEnd = 0;
        _cargoVehicle = null;
        _currentFinishPos = FinishPosition;
        _cooldownEnds.Clear();
        _isOutOfVehicle = false;

        Function.Call(Hash.SET_ENTITY_INVINCIBLE, Game.Player.Character, false);

        // 5 秒后回到 Waiting 状态
        Script.Wait(5000);
        _state = GameState.Waiting;
    }

    private void CleanupDeadEntities()
    {
        for (int i = _spawnedVehicles.Count - 1; i >= 0; i--)
        {
            if (_spawnedVehicles[i] == null || !_spawnedVehicles[i].Exists() || _spawnedVehicles[i].IsDead)
                _spawnedVehicles.RemoveAt(i);
        }
        for (int i = _spawnedPeds.Count - 1; i >= 0; i--)
        {
            if (_spawnedPeds[i] == null || !_spawnedPeds[i].Exists() || _spawnedPeds[i].IsDead)
                _spawnedPeds.RemoveAt(i);
        }
    }

    protected override void Dispose(bool disposing)
    {
        if (disposing)
        {
            CleanupAll();
            Tick -= OnTick;
        }
        base.Dispose(disposing);
    }
